code = """import json
import collections

# Load OrderItems
order_items_data = locals()['var_function-call-9657187622507777410']
# Load Cases (new with IDs)
cases_data = locals()['var_function-call-10168814404933614579']

def clean_id(i):
    if i and isinstance(i, str):
        return i.lstrip('#').strip()
    return i

target_order_items = set()
for item in order_items_data:
    oid = clean_id(item.get('OrderItemId'))
    if oid:
        target_order_items.add(oid)

issue_counts = collections.Counter()
matched_cases = []

for case in cases_data:
    oid = clean_id(case.get('orderitemid__c'))
    iid = clean_id(case.get('issueid__c'))
    cid = clean_id(case.get('id'))
    
    if oid and oid in target_order_items:
        if iid:
            issue_counts[iid] += 1
            matched_cases.append(cid)

result = {
    "most_frequent_issue_id": issue_counts.most_common(1)[0][0] if issue_counts else None,
    "count": issue_counts.most_common(1)[0][1] if issue_counts else 0,
    "all_counts": dict(issue_counts),
    "matched_cases_count": len(matched_cases)
}

print("__RESULT__:")
print(json.dumps(result))"""

